// R01-A03: Verify JWT đã hoàn tất ở node trước. Không decode JWT và không dựng SQL.
const request = $('Webhook Search').first().json;
const verifiedUser = $('🔐 Verify JWT').first().json;
const headers = request.headers || {};
const body = request.body || {};
const authHeader = String(headers.authorization || headers.Authorization || '').trim();

const fail = (message, status = 400) => [{ json: { error: true, status, message } }];
const textFilter = (value, name, maxLength) => {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value !== 'string') throw new Error(name + ' phải là chuỗi');
  const normalized = value.trim();
  if (!normalized) return null;
  if (normalized.length > maxLength) throw new Error(name + ' vượt quá ' + maxLength + ' ký tự');
  return normalized;
};
const enumFilter = (value, name) => {
  const normalized = textFilter(value, name, 50);
  if (normalized !== null && !/^[a-z][a-z0-9_]{0,49}$/.test(normalized)) {
    throw new Error(name + ' không đúng định dạng enum');
  }
  return normalized;
};

if (!verifiedUser.id) return fail('Không lấy được user.id từ bước xác thực', 401);
if (!/^Bearer\s+\S+$/i.test(authHeader)) return fail('Thiếu Authorization Bearer hợp lệ', 401);

let keyword;
let equipmentType;
let equipmentCode;
let ownerDepartment;
let documentType;
let sourceType;
let languageCode;
let status;
let translationStatus;
try {
  keyword = textFilter(body.keyword, 'keyword', 200);
  equipmentType = textFilter(body.equipment_type, 'equipment_type', 100);
  equipmentCode = textFilter(body.equipment_code, 'equipment_code', 100);
  ownerDepartment = textFilter(body.owner_department, 'owner_department', 100);
  documentType = enumFilter(body.document_type, 'document_type');
  sourceType = enumFilter(body.source_type, 'source_type');
  languageCode = enumFilter(body.language_code, 'language_code');
  status = enumFilter(body.status, 'status');
  translationStatus = enumFilter(body.translation_status, 'translation_status');
} catch (error) {
  return fail(error.message, 400);
}

if (body.include_superseded !== undefined && typeof body.include_superseded !== 'boolean') {
  return fail('include_superseded phải là boolean');
}
const limit = body.limit === undefined ? 50 : body.limit;
const offset = body.offset === undefined ? 0 : body.offset;
if (!Number.isInteger(limit) || limit < 1 || limit > 100) return fail('limit phải là số nguyên trong khoảng 1..100');
if (!Number.isInteger(offset) || offset < 0 || offset > 10000) return fail('offset phải là số nguyên trong khoảng 0..10000');

const rpcBody = {
  p_keyword: keyword,
  p_document_type: documentType,
  p_source_type: sourceType,
  p_language_code: languageCode,
  p_status: status,
  p_equipment_type: equipmentType,
  p_equipment_code: equipmentCode,
  p_owner_department: ownerDepartment,
  p_translation_status: translationStatus,
  p_include_superseded: body.include_superseded === true,
  p_limit: limit,
  p_offset: offset
};

return [{
  json: {
    error: false,
    verified_user_id: String(verifiedUser.id),
    authorization: authHeader.replace(/^bearer\s+/i, 'Bearer '),
    rpc_body: rpcBody,
    filters_applied: rpcBody
  }
}];

const raw = $input.first().json;
let payload = raw && raw.body !== undefined ? raw.body : raw;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch { payload = null; }
}
if (Array.isArray(payload) && payload.length === 1) payload = payload[0];

if (!payload || typeof payload !== 'object' || !Array.isArray(payload.documents)) {
  return [{ json: { error: true, status: 502, message: 'Phản hồi RPC không đúng contract' } }];
}

const allowedFields = [
  'id', 'document_group_id', 'document_code', 'document_title', 'document_type',
  'language_code', 'source_type', 'version', 'status', 'approved_for_ai_use',
  'translation_status', 'is_ai_translated', 'owner_department', 'equipment_type',
  'equipment_code', 'file_name', 'file_hash', 'page_count', 'chunk_count',
  'uploaded_at', 'reviewed_at', 'approved_at', 'effective_date'
];
const documents = payload.documents.map((document) => {
  const sanitized = {};
  for (const field of allowedFields) {
    if (Object.prototype.hasOwnProperty.call(document || {}, field)) sanitized[field] = document[field];
  }
  return sanitized;
});
const totalCount = Number(payload.total_count);
const limit = Number(payload.limit);
const offset = Number(payload.offset);
if (!Number.isInteger(totalCount) || totalCount < 0 || !Number.isInteger(limit) || !Number.isInteger(offset)) {
  return [{ json: { error: true, status: 502, message: 'Metadata phân trang RPC không đúng contract' } }];
}

return [{ json: {
  error: false,
  success: true,
  documents,
  total_count: totalCount,
  limit,
  offset,
  filters_applied: $('Validate Request').first().json.filters_applied
} }];

const error = $input.first().json || {};
const candidate = Number(error.statusCode || error.httpCode || error.status || error.cause?.statusCode || 0);
const status = [400, 401, 403].includes(candidate) ? candidate : 502;
const message = status === 401
  ? 'JWT không hợp lệ hoặc đã hết hạn'
  : status === 403
    ? 'Không có quyền tìm kiếm tài liệu theo yêu cầu'
    : status === 400
      ? 'Bộ lọc tìm kiếm không hợp lệ'
      : 'Dịch vụ tìm kiếm tài liệu tạm thời không khả dụng';
return [{ json: { error: true, status, message } }];
